const body = $input.first().json;

// La conversación llega en message.text
const conversacion = body.message?.text || '';

// Datos del contacto — ajusta los campos según tu payload de GHL
const contactId  = body.contactId  || body.contact_id  || '';
const telefono   = body.phone      || body.fromNumber  || '';
const locationId = body.locationId || body.location_id || '';

if (!conversacion) {
  throw new Error('No se recibió conversación en body.message.text');
}

return [{ json: { conversacion, contactId, telefono, locationId } }];

const raw = $input.first().json.message?.content ||
            $input.first().json.choices?.[0]?.message?.content || '{}';
let params;
try {
  params = JSON.parse(raw.replace(/```json|```/g, '').trim());
} catch(e) {
  params = { consulta_valida: false, razon_invalida: 'No pude interpretar los datos de la conversación.' };
}
const c = $('Extraer conversación').first().json;
return [{ json: { ...params, contactId: c.contactId, telefono: c.telefono, locationId: c.locationId } }];

const data = $input.first().json;
const razon = (data.razon_invalida || '').toLowerCase();
let pregunta = 'Para cotizar tu vuelo necesito un poco más de información. ';
if (razon.includes('origen'))       pregunta += '¿Desde qué ciudad vas a salir?';
else if (razon.includes('destino')) pregunta += '¿A qué ciudad quieres viajar?';
else if (razon.includes('fecha'))   pregunta += '¿En qué fecha aproximada quieres viajar?';
else pregunta += '¿Me puedes indicar desde dónde sales, a dónde vas y en qué fecha aproximada?';
return [{ json: {
  resultado: 'STOP', motivo: 'datos_incompletos',
  respuesta: pregunta,
  contactId: data.contactId, telefono: data.telefono, locationId: data.locationId
}}];

const params    = $input.first().json;
const pasajeros = Math.max(1, parseInt(params.pasajeros) || 1);

return params.fechas.map(fecha => ({
  json: {
    fecha,
    origen:    params.origen,
    destino:   params.destino,
    pasajeros,
    contactId:  params.contactId,
    telefono:   params.telefono,
    locationId: params.locationId,
    // SOLO IDA — siempre un único slice
    duffelBody: JSON.stringify({
      data: {
        slices: [{
          origin:         params.origen,
          destination:    params.destino,
          departure_date: fecha
        }],
        passengers:      Array.from({ length: pasajeros }, () => ({ type: 'adult' })),
        cabin_class:     'economy',
        max_connections: 2
      }
    })
  }
}));

// ══════════════════════════════════════════════════════════
//  COTIZADOR AÉREO — solo ida, precio real en COP
//  TRM fija:  3.700 COP por USD
//  Ganancia:  $1.290.000 COP fijos por boleto
//  STOP:      precio final (neto + ganancia) por pasajero > $4.400.000 COP
//  Maleta:    mostrar SIEMPRE carryon primero; maleta solo si no hay otra opción
// ══════════════════════════════════════════════════════════

const GANANCIA_POR_BOLETO = 1_290_000;   // COP fijos por boleto
const STOP_FINAL_POR_PAX  = 4_400_000;   // STOP si precio FINAL por pasajero supera esto
const MAX_ESCALA_MS       = 12 * 60 * 60 * 1000;
const COSTO_MALETA_EST    = 200_000;     // COP estimado maleta 23kg (si no está incluida)

const TASAS_COP = { USD: 3700, EUR: 4000, GBP: 4650, COP: 1, MXN: 190, BRL: 680, AUD: 2350 };
function toCOP(monto, moneda) {
  return Math.round(parseFloat(monto) * (TASAS_COP[moneda] || TASAS_COP.USD));
}

// ─── FILTROS ────────────────────────────────────────────
// Aeropuertos prohibidos como escala (por código IATA)
const ESCALAS_PROHIBIDAS_IATA = new Set(['ADZ', 'YYZ']);
// Países prohibidos como escala
const PAISES_PROHIBIDOS = new Set(['US']);

function tieneEscalaProhibida(o) {
  for (const slice of o.slices) {
    const segs = slice.segments;
    for (let i = 0; i < segs.length - 1; i++) {
      const dest     = segs[i].destination;
      const pais     = dest?.iata_country_code || '';
      const aeropuerto = dest?.iata_code || '';
      if (PAISES_PROHIBIDOS.has(pais)) return true;
      if (ESCALAS_PROHIBIDAS_IATA.has(aeropuerto)) return true;
    }
  }
  return false;
}

function tieneEscalaLarga(o) {
  for (const slice of o.slices) {
    const segs = slice.segments;
    for (let i = 0; i < segs.length - 1; i++) {
      const espera = new Date(segs[i+1].departing_at) - new Date(segs[i].arriving_at);
      if (espera > MAX_ESCALA_MS) return true;
    }
  }
  return false;
}

// ─── MALETA ─────────────────────────────────────────────
// Duffel retorna baggages[] por segmento×pasajero
// quantity > 0 en 'checked' = maleta en bodega incluida en la tarifa
function maletasIncluidasEnTarifa(o) {
  let qty = 0;
  try {
    for (const slice of o.slices)
      for (const seg of slice.segments)
        for (const pax of (seg.passengers || [])) {
          const c = (pax.baggages || []).find(b => b.type === 'checked');
          if (c && c.quantity > qty) qty = c.quantity;
        }
  } catch(e) {}
  return qty;
}

// ─── PRECIO ─────────────────────────────────────────────
function calcularPrecio(o, pasajeros) {
  const moneda       = o.total_currency || 'USD';
  const netoTotal    = toCOP(o.total_amount, moneda);
  const netoPorPax   = Math.round(netoTotal / pasajeros);
  const ganancia     = GANANCIA_POR_BOLETO * pasajeros;
  const finalTotal   = netoTotal + ganancia;
  const finalPorPax  = Math.round(finalTotal / pasajeros);
  return { netoTotal, netoPorPax, ganancia, finalTotal, finalPorPax };
}

// ─── MAIN ───────────────────────────────────────────────
const clienteData = $('Preparar 5 búsquedas Duffel').first().json;
const pasajeros   = clienteData.pasajeros || 1;

const todasOfertas = $input.all().flatMap(item =>
  (!item.json.errors && item.json.data) ? (item.json.data.offers || []) : []
);

const filtradas = todasOfertas.filter(o => !tieneEscalaProhibida(o) && !tieneEscalaLarga(o));

if (filtradas.length === 0) {
  return [{ json: {
    resultado:  'STOP',
    motivo:     'sin_resultados',
    respuesta:  '¿Tienes flexibilidad en las fechas o el origen? No encontré vuelos disponibles sin escalas en EE.UU. ni con escalas mayores a 12 horas para esas fechas.',
    contactId:  clienteData.contactId, telefono: clienteData.telefono, locationId: clienteData.locationId
  }}];
}

// Separar ofertas con SOLO CARRYON de las que incluyen maleta
const soloCarryon = filtradas.filter(o => maletasIncluidasEnTarifa(o) === 0);
const conMaleta   = filtradas.filter(o => maletasIncluidasEnTarifa(o) > 0);

// Preferir siempre carryon; si no hay, usar las que incluyen maleta
const poolPreferido = soloCarryon.length > 0 ? soloCarryon : conMaleta;
const incluyeMaleta = soloCarryon.length === 0;  // flag para avisar al cliente

// Ordenar por precio neto por pasajero ascendente
const conPrecio = poolPreferido
  .map(o => ({ oferta: o, precio: calcularPrecio(o, pasajeros) }))
  .sort((a, b) => a.precio.netoPorPax - b.precio.netoPorPax);

const { oferta: mejor, precio } = conPrecio[0];

// STOP evaluado sobre precio FINAL (neto + ganancia) por pasajero
if (precio.finalPorPax > STOP_FINAL_POR_PAX) {
  return [{ json: {
    resultado:  'STOP',
    motivo:     'precio_excedido',
    respuesta:  `El precio más bajo disponible es $${precio.finalPorPax.toLocaleString('es-CO')} COP por persona, lo cual supera el presupuesto máximo disponible.`,
    contactId:  clienteData.contactId, telefono: clienteData.telefono, locationId: clienteData.locationId
  }}];
}

const maletas    = maletasIncluidasEnTarifa(mejor);
const segs       = mejor.slices[0].segments;
const salida     = new Date(segs[0].departing_at);
const llegada    = new Date(segs[segs.length - 1].arriving_at);
const aerolinea  = segs[0].operating_carrier?.name || segs[0].marketing_carrier?.name || 'N/D';
const origenCod  = segs[0].origin?.iata_code || clienteData.origen;
const destinoCod = segs[segs.length - 1].destination?.iata_code || clienteData.destino;
const numEscalas = segs.length - 1;
const detalleEscalas = numEscalas === 0
  ? 'Vuelo directo'
  : `${numEscalas} escala(s) vía ${segs.slice(0, -1).map(s => s.destination?.iata_code).join(', ')}`;

const fechaFormato = salida.toLocaleDateString('es-CO', { weekday:'long', year:'numeric', month:'long', day:'numeric' });
const horaS = salida.toLocaleTimeString('es-CO', { hour:'2-digit', minute:'2-digit' });
const horaL = llegada.toLocaleTimeString('es-CO', { hour:'2-digit', minute:'2-digit' });

// Línea de equipaje según lo que incluye la tarifa
let lineaEquipaje;
if (!incluyeMaleta) {
  // Precio carryon — mostrar también costo estimado con maleta
  const precioConMaletaPax   = precio.finalPorPax + COSTO_MALETA_EST;
  const precioConMaletaTotal = precio.finalTotal + (COSTO_MALETA_EST * pasajeros);
  lineaEquipaje = pasajeros > 1
    ? `   • ✅ Solo carry-on: $${precio.finalPorPax.toLocaleString('es-CO')} COP/persona ($${precio.finalTotal.toLocaleString('es-CO')} COP total)\n` +
      `   • 🧳 Con maleta 23kg: $${precioConMaletaPax.toLocaleString('es-CO')} COP/persona ($${precioConMaletaTotal.toLocaleString('es-CO')} COP total) _(estimado)_`
    : `   • ✅ Solo carry-on: $${precio.finalPorPax.toLocaleString('es-CO')} COP\n` +
      `   • 🧳 Con maleta 23kg: $${precioConMaletaPax.toLocaleString('es-CO')} COP _(estimado)_`;
} else {
  // Solo había tarifas con maleta incluida
  lineaEquipaje = pasajeros > 1
    ? `   • 🧳 Incluye maleta en bodega: $${precio.finalPorPax.toLocaleString('es-CO')} COP/persona ($${precio.finalTotal.toLocaleString('es-CO')} COP total)\n` +
      `   _(No encontramos tarifa solo carry-on para estas fechas)_`
    : `   • 🧳 Incluye maleta en bodega: $${precio.finalPorPax.toLocaleString('es-CO')} COP\n` +
      `   _(No encontramos tarifa solo carry-on para estas fechas)_`;
}

const respuesta =
  `✈️ *Cotización — Solo Ida*\n\n` +
  `📍 *Ruta:* ${origenCod} → ${destinoCod}\n` +
  `🗓️ *Fecha:* ${fechaFormato}\n` +
  `🕐 *Salida:* ${horaS} | *Llegada:* ${horaL}\n` +
  `🛫 *Aerolínea:* ${aerolinea}\n` +
  `🔁 *Escalas:* ${detalleEscalas}\n\n` +
  `💰 *Precios:*\n` +
  `${lineaEquipaje}\n\n` +
  `¿Te interesa este vuelo o quieres que busque otras opciones?`;

return [{ json: {
  resultado: 'OK',
  respuesta,
  cotizacion: {
    aerolinea, origenCod, destinoCod, fechaFormato,
    horaSalida: horaS, horaLlegada: horaL,
    escalas: numEscalas, detalleEscalas,
    tarifaCarryon:   !incluyeMaleta,
    maletas:         maletas,
    precioPorPax:    precio.finalPorPax,
    precioTotal:     precio.finalTotal,
    moneda:          'COP',
    pasajeros
  },
  _interno: {
    netoTotal:    precio.netoTotal,
    netoPorPax:   precio.netoPorPax,
    ganancia:     precio.ganancia
  },
  contactId:  clienteData.contactId,
  telefono:   clienteData.telefono,
  locationId: clienteData.locationId
}}];
